import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] points = new int[N][2];
            for (int i = 0; i < N; i++) {
                points[i][0] = sc.nextInt();
                points[i][1] = sc.nextInt();
            }
            int min_distance = Integer.MAX_VALUE;
            int result = 0;
            int[] perm = new int[N];
            for (int i = 0; i < N; i++) {
                perm[i] = i;
            }
            do {
                int distance = 0;
                for (int i = 0; i < N - 1; i++) {
                    distance += Math.abs(points[perm[i]][0] - points[perm[i + 1]][0]) > Math.abs(points[perm[i]][1] - points[perm[i + 1]][1]) ? Math.abs(points[perm[i]][0] - points[perm[i + 1]][0]) : Math.abs(points[perm[i]][1] - points[perm[i + 1]][1]);
                }
                if (distance < min_distance) {
                    min_distance = distance;
                    result = 0;
                    for (int i = 0; i < N; i++) {
                        result ^= perm[i] + 1;
                    }
                } else if (distance == min_distance) {
                    int temp = 0;
                    for (int i = 0; i < N; i++) {
                        temp ^= perm[i] + 1;
                    }
                    if (temp < result) {
                        result = temp;
                    }
                }
            } while (nextPermutation(perm));
            System.out.println(min_distance + " " + result);
        }
    }

    public static boolean nextPermutation(int[] array) {
        int i = array.length - 2;
        while (i >= 0 && array[i] >= array[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = array.length - 1;
        while (j > i && array[j] <= array[i]) {
            j--;
        }
        swap(array, i, j);
        reverse(array, i + 1);
        return true;
    }

    public static void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }

    public static void reverse(int[] array, int start) {
        int end = array.length - 1;
        while (start < end) {
            swap(array, start, end);
            start++;
            end--;
        }
    }
}

