const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const points = [];
    for (let j = 0; j < N; j++) {
        points.push(readline().split(' ').map(Number));
    }
    let min_distance = Infinity;
    let result = 0;
    const permute = (arr, m = []) => {
        if (arr.length === 0) {
            let distance = 0;
            for (let k = 0; k < N - 1; k++) {
                distance += Math.min(Math.abs(points[m[k]][0] - points[m[k + 1]][0]), Math.abs(points[m[k]][1] - points[m[k + 1]][1]));
            }
            if (distance < min_distance) {
                min_distance = distance;
                result = 0;
                for (let k = 0; k < N; k++) {
                    result ^= m[k] + 1;
                }
            } else if (distance === min_distance) {
                let temp = 0;
                for (let k = 0; k < N; k++) {
                    temp ^= m[k] + 1;
                }
                if (temp < result) {
                    result = temp;
                }
            }
        } else {
            for (let j = 0; j < arr.length; j++) {
                let curr = arr.slice();
                let rest = curr.slice(0, j).concat(curr.slice(j + 1));
                permute(rest, m.concat([arr[j]]));
            }
        }
    };
    permute([...Array(N).keys()]);
    console.log(min_distance, result);
}
